import './TimelineCollapse.scss';

import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../../helpers/classnames';
import { Icon } from '../../Icon';
import { Typography } from '../../Typography';
import { TimelineAtom } from '../TimelineAtom';
import type { TimelineCollapseProps } from './TimelineCollapse.types';

export const TimelineCollapse: FC<TimelineCollapseProps> = ({
	onCollapse,
	collapsed,
	className,
	takenStepsCount,
	amountStepsCount,
	completed = false,
	pastSteps = false,
	children,
}) => {
	/** Рассчёт выполненных шагов */
	const takenStepsText = completed ? amountStepsCount : takenStepsCount;

	return (
		<div data-testid="TimelineCollapse" className={classNames('dsb_timeline-collapse', className)}>
			{pastSteps && (
				<div className="dsb_timeline-collapse-body">
					<TimelineAtom type="active" position="top" />
					<div
						onClick={onCollapse}
						onKeyDown={event => event.key === 'Enter' && onCollapse()}
						role="button"
						tabIndex={0}
						className="dsb_timeline-collapse-body-title"
					>
						<Typography
							variant="body2"
							className={classNames(
								'dsb_timeline-collapse-body-title-text',
								collapsed && 'dsb_timeline-collapse-body-title-text__collapsed',
							)}
						>
							{collapsed ? `Завершено ${takenStepsText} из ${amountStepsCount} этапов` : 'Свернуть'}
						</Typography>
						<Icon
							size="medium"
							iconName={Icons.NavArrowUp}
							className={classNames(
								'dsb_timeline-collapse-body-title-icon',
								collapsed && 'dsb_timeline-collapse-body-title-icon__collapsed',
							)}
						/>
					</div>
				</div>
			)}
			<div
				className={classNames('dsb_timeline-collapse-content', collapsed && 'dsb_timeline-collapse-content__collapsed')}
			>
				{children}
			</div>
		</div>
	);
};
